async def _post_insight(tool_name: str, status: str, duration_ms: float,
                        error: Optional[str] = None,
                        input_size: int = 0, output_size: int = 0):
    payload = {
        "server_id": SERVER_ID,
        "tool_name": tool_name,
        "request_type": "tool",
        "execution_time_ms": duration_ms,
        "status": status,
        "error": error,
        "input_size": input_size,
        "output_size": output_size,
        "timestamp": datetime.now(UTC).isoformat(),
    }
    _url = HUB_API_URL.rstrip('/') + '/api/insights/track'
    try:
        async with httpx.AsyncClient(timeout=5.0) as _c:
            _r = await _c.post(_url, json=payload)
            logger.info(f"[insight] {tool_name} {status} {duration_ms:.0f}ms -> HTTP {_r.status_code}")
    except Exception as _e:
        logger.warning(f"[insight] POST failed: {_e}")


