from starlette.applications import Starlette
from starlette.responses import JSONResponse, Response
from starlette.routing import Route
from starlette.requests import Request as StarletteRequest

if __name__ == "__main__":
    mcp.run()
else:
    try:
        from mcp.server.sse import SseServerTransport
        _transport = SseServerTransport("/messages/")

        async def _sse_endpoint(request):
            _inner = getattr(mcp, '_mcp_server', None) or getattr(mcp, 'server', None) or mcp
            async with _transport.connect_sse(request.scope, request.receive, request._send) as (r, w):
                await _inner.run(r, w, _inner.create_initialization_options(), raise_exceptions=False)
            return Response()

        async def _sse_post_endpoint(request: StarletteRequest):
            raw = await request.body()
            try:
                body = json.loads(raw)
                method = body.get('method')
                if method == 'initialize':
                    return JSONResponse({'server': getattr(mcp, 'name', 'mcp-server'), 'capabilities': {'tools': True, 'resources': False, 'prompts': False}})
                elif method == 'tools/list':
                    tools_list = []
                    try:
                        for t in getattr(mcp, '_tools', {}).values():
                            tools_list.append({'name': t.name, 'description': getattr(t, 'description', '')})
                    except:
                        pass
                    return JSONResponse({'tools': tools_list})
                elif method == 'tools/call':
                    params = body.get('params', {})
                    name = params.get('name')
                    args = params.get('arguments', {})
                    _start = time.perf_counter()
                    _status = 'success'
                    _error = None
                    try:
                        sanitized = ''.join(c if c.isalnum() else '_' for c in name)
                        if sanitized and sanitized[0].isdigit(): sanitized = 't_' + sanitized
                        tool_fn = globals().get(sanitized)
                        if tool_fn:
                            res = await tool_fn(**args)
                            return JSONResponse({'content': [{'type': 'text', 'text': str(res)}]})
                        else:
                            raise ValueError(f'Tool {name} not found')
                    except Exception as e:
                        _status = 'error'
                        _error = str(e)
                        return JSONResponse({'isError': True, 'content': [{'type': 'text', 'text': str(e)}]})
                    finally:
                        _dur = (time.perf_counter() - _start) * 1000
                        await _post_insight(name, _status, _dur, _error, len(raw), 0)
                return JSONResponse({'error': 'Unsupported method'}, status_code=400)
            except Exception as e:
                return JSONResponse({'error': str(e)}, status_code=500)

        async def _messages_endpoint(request: StarletteRequest):
            raw = await request.body()
            _start = time.perf_counter()
            _tool_name = None
            _is_tool_call = False
            try:
                _msg = json.loads(raw)
                if _msg.get('method') == 'tools/call':
                    _is_tool_call = True
                    _tool_name = (_msg.get('params') or {}).get('name', 'unknown')
            except Exception:
                pass
            async def _replay(): return {'type': 'http.request', 'body': raw, 'more_body': False}
            _status = 'success'
            _error = None
            try:
                await _transport.handle_post_message(request.scope, _replay, request._send)
            except Exception as _exc:
                _status = 'error'
                _error = str(_exc)
            finally:
                if _is_tool_call and _tool_name:
                    _dur = (time.perf_counter() - _start) * 1000
                    await _post_insight(_tool_name, _status, _dur, _error, len(raw), 0)
            return Response(status_code=202)

        app = Starlette(routes=[
            Route("/", _root_handler),
            Route("/sse", _sse_endpoint, methods=["GET"]),
            Route("/sse", _sse_post_endpoint, methods=["POST"]),
            Route("/messages/", _messages_endpoint, methods=["POST"]),
            Route("/messages", _messages_endpoint, methods=["POST"]),
            Route("/{path:path}", _root_handler),
        ])
    except Exception as _e:
        logger.error(f"Startup failed: {_e}")
        async def _err(r): return JSONResponse({'status': 'error', 'detail': str(_e)}, status_code=500)
        app = Starlette(routes=[Route('/', _err), Route('/{path:path}', _err)])
